{
  "business_expectations": [
    {
      "expectation_id": "年龄条件解析为 clientAge >= 25",
      "description": "用户查询“25岁以上”，结合项目标注“30岁以上→GTE 30”，应解析为年龄大于等于25岁",
      "expected_outcome": "conditions 中包含一项，field='clientAge', operator='GTE', value=25",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "性别条件解析为 clientSex = 女",
      "description": "用户查询“女性客户”，应映射到客户本人性别为女",
      "expected_outcome": "conditions 中包含一项，field='clientSex', operator='MATCH', value='女'",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "年缴保费条件解析为 annPremSegNum > 10000",
      "description": "用户查询“年缴保费大于1万”，应转换为年缴保费大于10000元，使用GT操作符（注解：该字段仅支持大于关系）",
      "expected_outcome": "conditions 中包含一项，field='annPremSegNum', operator='GT', value=10000",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "条件逻辑关系为 AND",
      "description": "三个筛选条件应当以“且”的组合关系生效",
      "expected_outcome": "query_logic 字段值为 'AND'",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "条件数量恰好为 3，无冗余或遗漏",
      "description": "最终输出的条件数组应恰好包含上述三个条件，不多不少",
      "expected_outcome": "conditions 数组长度为 3，且其中每一项都属于年龄/性别/保费，不含无关字段",
      "blocking_level": "non-blocking"
    }
  ],
  "expected": {
    "code": 200,
    "msg": "成功",
    "query": "25岁以上的女性客户，年缴保费大于1万",
    "conditions": [
      {
        "field": "clientAge",
        "operator": "GTE",
        "value": 25
      },
      {
        "field": "clientSex",
        "operator": "MATCH",
        "value": "女"
      },
      {
        "field": "annPremSegNum",
        "operator": "GT",
        "value": 10000
      }
    ],
    "robot_text": null,
    "end_flag": null,
    "trace_id": null,
    "query_logic": "AND",
    "matched_level": null,
    "matched_patterns": null,
    "rewritten_query": null,
    "intent_summary": null,
    "confidence": null,
    "cost_times": null
  },
  "reconstructed_intent": "用户希望查找同时满足三个条件的客户：本人年龄在25岁及以上、本人性别为女、且年缴保费大于10,000元。三个条件为“且”的关系，无家庭成员、无保单状态等额外限制。",
  "judge_basis": "基于项目 client_search 的字段能力定义、增强规则和字段注解：clientAge 注解说明“30岁以上→GTE 30”，因此“25岁以上”按同样口径解释为 GTE 25；clientSex 仅支持 MATCH，枚举值使用“男/女”；annPremSegNum 描述为“年缴保费金额（大于）”，且注解明确“仅包含大于关系”，操作符使用 GT；“1万”统一按 1万=10000 元换算。条件组合逻辑为 AND。",
  "reference_generation_basis": {
    "reasoning": "从用户查询中提取三个独立筛选维度：年龄、性别、保费。年龄根据能力标注“30岁以上→GTE 30”推断“25岁以上”为 GTE 25；性别直接映射 MATCH 女；保费将中文“1万”转换为 10000 元，并应用 GT 操作符。三个条件无冲突，以 AND 组合输出。",
    "key_documents": [
      "clientAge field notes: GT语义会自动转换为GTE并对值+1，30岁以上→GTE 30",
      "annPremSegNum field notes: 仅包含大于关系，不包含等于",
      "clientSex operators: [EXISTS, MATCH, NOT_EXISTS]",
      "enhanced_rules: 年龄-及以上规则 (\\d+)岁?及?以上 -> GTE int"
    ]
  }
}

